'use client';

import { useState } from 'react';
import { X } from 'lucide-react';
import Sidebar from '@/components/sidebar';
import MaryDashboard from '@/components/mary-dashboard';
import PatientsView from '@/components/patients-view';

export default function Home() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'patients'>('dashboard');
  const [showQuickCreate, setShowQuickCreate] = useState(false);

  return (
    <div className="flex h-screen bg-gradient-to-br from-blue-50 via-purple-50 to-blue-100">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        onQuickCreate={() => setShowQuickCreate(true)}
      />
      <main className="flex-1 overflow-hidden">
        {activeTab === 'dashboard' ? <MaryDashboard /> : <PatientsView />}
      </main>

      {/* Quick Create Modal */}
      {showQuickCreate && (
        <>
          {/* Backdrop */}
          <div 
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40"
            onClick={() => setShowQuickCreate(false)}
          />
          {/* Modal */}
          <div className="fixed inset-0 flex items-center justify-center z-50 pointer-events-none">
            <div className="bg-white rounded-3xl shadow-2xl p-8 w-full max-w-md pointer-events-auto">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold text-gray-900">Quick Create</h2>
                <button
                  onClick={() => setShowQuickCreate(false)}
                  className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                >
                  <X size={24} className="text-gray-500" />
                </button>
              </div>

              <div className="space-y-3">
                <button className="w-full bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-xl px-4 py-3 font-semibold hover:shadow-lg transition-shadow text-left flex items-center gap-3">
                  <span>📋</span>
                  <span>Create Task</span>
                </button>
                <button className="w-full bg-gradient-to-r from-green-500 to-green-600 text-white rounded-xl px-4 py-3 font-semibold hover:shadow-lg transition-shadow text-left flex items-center gap-3">
                  <span>📝</span>
                  <span>Add Note</span>
                </button>
                <button className="w-full bg-gradient-to-r from-purple-500 to-purple-600 text-white rounded-xl px-4 py-3 font-semibold hover:shadow-lg transition-shadow text-left flex items-center gap-3">
                  <span>🏥</span>
                  <span>Create Reminder</span>
                </button>
                <button className="w-full bg-gradient-to-r from-orange-500 to-orange-600 text-white rounded-xl px-4 py-3 font-semibold hover:shadow-lg transition-shadow text-left flex items-center gap-3">
                  <span>📞</span>
                  <span>New Contact</span>
                </button>
              </div>

              <button
                onClick={() => setShowQuickCreate(false)}
                className="w-full mt-6 px-4 py-3 text-gray-700 hover:bg-gray-100 rounded-xl transition-colors font-semibold"
              >
                Cancel
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
